import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  Typography, 
  Card, 
  Table, 
  Tag, 
  Button, 
  Space, 
  Input,
  Tooltip,
  Modal,
  Select,
  InputNumber,
  theme,
  message,
  Flex
} from "antd";
import { 
  ReloadOutlined, 
  PlusOutlined, 
  EditOutlined, 
  DeleteOutlined, 
  CaretRightOutlined, 
  PauseOutlined,
  SearchOutlined,
  FilterOutlined,
  FileTextOutlined,
  CloseOutlined,
  QuestionCircleOutlined,
  LinkOutlined,
  DisconnectOutlined
} from "@ant-design/icons";

const { Text, Title } = Typography;

const SchedulerManagementPage: React.FC = () => {
  const { t } = useTranslation(["quarantine", "management"]);
  const { token } = theme.useToken();
  const [selectedRowKeys, setSelectedRowKeys] = useState<React.Key[]>(["2"]);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [isStopConfirmOpen, setIsStopConfirmOpen] = useState(false);
  const [isRunConfirmOpen, setIsRunConfirmOpen] = useState(false);

  const schedulerData = [
    { key: "1", status: "online", name: "세계감염병현황", id: "DssStatusJob", cycle: "30분", params: '{"url":"http://222.107.32.38:1012/api/information/nco..."}', remarks: "국가별 감염병 발생현황" },
    { key: "2", status: "online", name: "위험등급", id: "OverseaRiskInfoJob", cycle: "1분", params: '{"url":"http://222.107.32.38:1012/api/information/risk"}', remarks: "국가별 감염병 위험등급 조회" },
    { key: "3", status: "online", name: "장비알림", id: "AlarmServiceJob", cycle: "30초", params: '{"domainCd":"BTP"}', remarks: "장비알림조회" },
    { key: "4", status: "online", name: "시나리오 체크", id: "CheckNewScnrJob", cycle: "15초", params: '{"domainCd":"BTP"}', remarks: "시나리오 체크" },
    { key: "5", status: "online", name: "시나리오 완료 체크", id: "CheckCmpltScnrJob", cycle: "15초", params: '{"domainCd":"BTP"}', remarks: "시나리오 완료 체크" },
    { key: "6", status: "online", name: "실시간항공기운항현황", id: "TerminalScheduleJob", cycle: "1분", params: '{"url":"http://openapi.airport.co.kr/service/rest/FlightS..."}', remarks: "실시간항공기운항현황" },
    { key: "7", status: "online", name: "디바이스 상태 체크", id: "DeviceStatusJob", cycle: "30분", params: '{"domainCd":"BTP", "start":"-30m"}', remarks: "디바이스 상태 체크" }
  ];

  const handleRefresh = () => {
    const hide = message.loading(t("management:refresh") + "...", 0);
    setTimeout(() => {
      hide();
      message.success(t("management:cmdSent"));
    }, 800);
  };

  const columns = [
    {
      title: t("management:communicationCheck"),
      dataIndex: "status",
      key: "status",
      align: "center" as const,
      width: 100,
      render: (status: string) => <div className="w-3 h-3 rounded-full shadow-lg mx-auto" style={{ background: token.colorSuccess, boxShadow: `0 0 8px ${token.colorSuccess}` }} />
    },
    {
      title: t("management:jobName"),
      dataIndex: "name",
      key: "name",
      render: (text: string) => <Text style={{ color: token.colorTextSecondary, fontWeight: "bold", fontSize: 14 }}>{text}</Text>
    },
    {
      title: t("management:jobId"),
      dataIndex: "id",
      key: "id",
      render: (text: string) => <Text className="font-mono" style={{ color: token.colorTextQuaternary, fontSize: 13 }}>{text}</Text>
    },
    {
      title: t("management:schedulerConfig.interval"),
      dataIndex: "cycle",
      key: "cycle",
      render: (text: string) => <Text style={{ color: token.colorPrimary, fontWeight: "bold", fontSize: 13 }}>{text}</Text>
    },
    {
      title: t("management:parameter"),
      dataIndex: "params",
      key: "params",
      render: (text: string) => <Text className="font-mono italic" style={{ color: token.colorTextQuaternary, fontSize: 12 }}>{text}</Text>
    },
    {
      title: t("management:remarks"),
      dataIndex: "remarks",
      key: "remarks",
      render: (text: string) => <Text style={{ color: token.colorTextQuaternary, fontSize: 13 }}>{text}</Text>
    }
  ];

  return (
    <div className="h-full p-6 overflow-hidden flex flex-col relative" style={{ background: token.colorBgLayout }}>
      {/* Header & Toolbar */}
      <div className="flex justify-between items-center mb-6">
         <Space size="large">
            <Title level={4} className="font-bold m-0" style={{ color: token.colorText }}>{t("quarantine:navigation.schedulerMng")}</Title>
            <Space className="p-1 px-3 rounded-lg border" style={{ background: token.colorBgContainer, borderColor: token.colorBorderSecondary }}>
               <Tooltip title={t("management:search")}><SearchOutlined style={{ color: token.colorTextQuaternary }} className="cursor-pointer" /></Tooltip>
               <Tooltip title={t("management:log")}><FileTextOutlined style={{ color: token.colorTextQuaternary }} className="cursor-pointer" /></Tooltip>
            </Space>
         </Space>

         <Space size="small">
            {[
              { label: t("management:refresh"), icon: <ReloadOutlined />, onClick: handleRefresh },
              { label: t("management:add"), icon: <PlusOutlined />, className: "btn-vibrant-primary", onClick: () => { setEditingItem(null); setIsEditModalOpen(true); } },
              { label: t("management:edit"), icon: <EditOutlined />, className: "btn-vibrant-primary", onClick: () => { setEditingItem(schedulerData.find(d => d.key === selectedRowKeys[0]) || schedulerData[0]); setIsEditModalOpen(true); } },
              { label: t("management:delete"), icon: <DeleteOutlined />, className: "btn-vibrant-secondary", onClick: () => { message.warning(t("management:cmdSent")); } },
              { label: t("management:link"), icon: <LinkOutlined />, className: "btn-vibrant-primary", onClick: () => setIsRunConfirmOpen(true) },
              { label: t("management:unlink"), icon: <DisconnectOutlined />, className: "btn-vibrant-secondary", onClick: () => setIsStopConfirmOpen(true) }
            ].map(btn => (
               <Button 
                 key={btn.label}
                 className={`${btn.className || "btn-vibrant-primary"} border-none h-8 px-4`}
                 icon={btn.icon}
                 onClick={btn.onClick}
               >
                 {btn.label}
               </Button>
            ))}
         </Space>
      </div>

      {/* Main Table Content */}
      <Card 
        className="border flex-1 overflow-hidden" 
        style={{ background: token.colorBgContainer, borderColor: token.colorBorderSecondary }}
        styles={{ body: { padding: 0, height: '100%', overflow: 'hidden' } }}
      >
        <Table 
          rowSelection={{
            type: 'checkbox',
            selectedRowKeys,
            onChange: (keys) => setSelectedRowKeys(keys),
          }}
          columns={columns} 
          dataSource={schedulerData} 
          pagination={false}
          className="custom-scheduler-table"
          rowClassName={(record) => selectedRowKeys.includes(record.key) ? 'selected-row' : ''}
          scroll={{ y: 'calc(100vh - 280px)' }}
        />
      </Card>

      {/* Edit Modal (Add/Edit) */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{editingItem ? t("management:edit") : t("management:add")}</Text>}
        open={isEditModalOpen}
        onCancel={() => setIsEditModalOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsEditModalOpen(false)}>
              {t("common:no")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { message.success(t("common:saveSuccess")); setIsEditModalOpen(false); }}>
              {t("common:yes")}
            </Button>
          </Flex>
        )}
        centered
        width={600}
        styles={{ 
          mask: { backdropFilter: "blur(12px)" }, 
          body: { padding: "32px 24px" },
          header: { padding: "24px 24px 0", marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <div className="space-y-6">
           <FormItem label={t("management:jobName")} required>
              <Input defaultValue="위험등급" variant="borderless" style={{ background: token.colorBgLayout, border: `1px solid ${token.colorBorderSecondary}`, color: token.colorText, borderRadius: 4, padding: "8px 12px" }} />
           </FormItem>
           <FormItem label={t("management:jobId")} required>
              <Input defaultValue="OverseaRiskInfoJob" variant="borderless" style={{ background: token.colorBgLayout, border: `1px solid ${token.colorBorderSecondary}`, color: token.colorText, borderRadius: 4, padding: "8px 12px" }} />
           </FormItem>
           <FormItem label={t("quarantine:common.status")} required>
              <Select defaultValue="use" variant="borderless" style={{ background: token.colorBgLayout, borderRadius: 4, border: `1px solid ${token.colorBorderSecondary}`, width: '100%', height: 40 }}>
                 <Select.Option value="use">{t("quarantine:common.online")}</Select.Option>
                 <Select.Option value="stop">{t("quarantine:common.offline")}</Select.Option>
              </Select>
           </FormItem>
           <FormItem label={t("management:schedulerConfig.interval")} required>
              <div className="flex gap-4">
                 <InputNumber defaultValue={1} variant="borderless" style={{ background: token.colorBgLayout, width: '100%', border: `1px solid ${token.colorBorderSecondary}`, color: token.colorText, borderRadius: 4, padding: "4px 0" }} />
                 <Select defaultValue="min" variant="borderless" style={{ background: token.colorBgLayout, borderRadius: 4, border: `1px solid ${token.colorBorderSecondary}`, width: 100, height: 40 }}>
                    <Select.Option value="min">{t("management:minutes")}</Select.Option>
                    <Select.Option value="sec">{t("management:seconds")}</Select.Option>
                 </Select>
              </div>
           </FormItem>
           <FormItem label={t("management:parameter")} required>
              <div className="flex gap-2">
                 <Input defaultValue="url" style={{ background: token.colorBgLayout, border: `1px solid ${token.colorBorderSecondary}`, color: token.colorText, borderRadius: 4, width: 120 }} />
                 <Input defaultValue="http://222.107.32.38:1012/api/information/risk" className="flex-1" style={{ background: token.colorBgLayout, border: `1px solid ${token.colorBorderSecondary}`, color: token.colorText, borderRadius: 4 }} />
                 <Button className="flex items-center justify-center p-0" style={{ background: token.colorFillAlter, borderColor: token.colorBorderSecondary, color: token.colorTextQuaternary, width: 40, height: 40, borderRadius: 8 }}><PlusOutlined /></Button>
              </div>
           </FormItem>
           <FormItem label={t("management:remarks")}>
              <Input defaultValue="국가별 감염병 위험등급 조회" variant="borderless" style={{ background: token.colorBgLayout, border: `1px solid ${token.colorBorderSecondary}`, color: token.colorText, borderRadius: 4, padding: "8px 12px" }} />
           </FormItem>
        </div>
      </Modal>

      {/* Stop Confirmation Modal */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{t("management:unlink")}</Text>}
        open={isStopConfirmOpen}
        onCancel={() => setIsStopConfirmOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsStopConfirmOpen(false)}>
              {t("management:no")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { message.success(t("management:cmdSent")); setIsStopConfirmOpen(false); }}>
              {t("management:yes")}
            </Button>
          </Flex>
        )}
        centered
        width={450}
        styles={{ 
          mask: { backdropFilter: "blur(12px)" }, 
          body: { padding: "32px 24px" }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <div className="flex flex-col items-center gap-4 py-4">
           <QuestionCircleOutlined style={{ color: token.colorWarning, fontSize: 48, marginBottom: 16 }} />
           <Text style={{ color: token.colorText, fontSize: 16, fontWeight: "bold", textAlign: "center" }}>{t("management:unlinkConfirm")}</Text>
        </div>
      </Modal>

      {/* Run Confirmation Modal */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{t("management:link")}</Text>}
        open={isRunConfirmOpen}
        onCancel={() => setIsRunConfirmOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsRunConfirmOpen(false)}>
              {t("management:no")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { message.success(t("management:cmdSent")); setIsRunConfirmOpen(false); }}>
              {t("management:yes")}
            </Button>
          </Flex>
        )}
        centered
        width={450}
        styles={{ 
          mask: { backdropFilter: "blur(12px)" }, 
          body: { padding: "32px 24px" }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <div className="flex flex-col items-center gap-4 py-4">
           <QuestionCircleOutlined style={{ color: token.colorPrimary, fontSize: 48, marginBottom: 16 }} />
           <Text style={{ color: token.colorText, fontSize: 16, fontWeight: "bold", textAlign: "center" }}>{t("management:runConfirm")}</Text>
        </div>
      </Modal>

      <style>{`
        .custom-scheduler-table .ant-table { background: transparent !important; color: ${token.colorText} !important; }
        .custom-scheduler-table .ant-table-thead > tr > th { 
           background: ${token.colorFillAlter} !important; 
           color: ${token.colorTextDescription} !important; 
           font-size: 13px !important; 
           font-weight: bold !important; 
           border-bottom: 2px solid ${token.colorBorderSecondary} !important; 
           text-transform: none; 
        }
        .custom-scheduler-table .ant-table-tbody > tr > td { border-bottom: 1px solid ${token.colorBorderSecondary} !important; padding: 12px 16px !important; font-size: 14px; }
        .selected-row > td { background: ${token.colorPrimary}26 !important; }
        .ant-checkbox-inner { background: transparent !important; border: 1px solid ${token.colorBorder} !important; border-radius: 4px !important; }
        .ant-checkbox-checked .ant-checkbox-inner { background: ${token.colorPrimary} !important; border-color: ${token.colorPrimary} !important; }
        .ant-modal-content { border-radius: 16px !important; overflow: hidden; border: 1px solid ${token.colorBorderSecondary}; }

        /* Solid Button System (High Contrast & Unified Blue - Per User Screenshot) */
        .btn-vibrant-primary { 
          background: ${token.colorPrimary} !important; 
          border-color: ${token.colorPrimary} !important; 
          color: #fff !important; 
          font-weight: bold !important; 
          border-radius: 6px !important; 
          transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .btn-vibrant-primary:hover {
          filter: brightness(1.1) saturate(1.1);
          box-shadow: 0 4px 12px ${token.colorPrimary}40;
          transform: translateY(-1px);
        }
        .btn-vibrant-secondary {
          background: ${token.colorFillAlter} !important;
          border: 1px solid ${token.colorBorderSecondary} !important;
          color: ${token.colorTextDescription} !important;
          font-weight: bold !important;
          border-radius: 6px !important;
          transition: all 0.2s ease;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .btn-vibrant-secondary:hover {
          background: ${token.colorFillSecondary} !important;
          color: ${token.colorText} !important;
          border-color: ${token.colorBorder} !important;
        }
      `}</style>
    </div>
  );
};

const FormItem = ({ label, children, required }: any) => {
  const { token } = theme.useToken();
  return (
    <div className="flex items-center">
      <div className="w-40 flex items-center gap-2">
        {required && <div className="w-1.5 h-1.5 rounded-full" style={{ background: token.colorError }} />}
        <Text className="font-bold uppercase" style={{ color: token.colorTextQuaternary, fontSize: 13 }}>{label}</Text>
      </div>
      <div className="flex-1">{children}</div>
    </div>
  );
};

export default SchedulerManagementPage;
